const contacts = $json.contacts || [];
const readyContacts = contacts.filter(c => c.customField?.RbxKguAHbRjqH5K5922f?.status === 'Ready');

return readyContacts.map(contact => {
  const cf = contact.customField?.RbxKguAHbRjqH5K5922f || {};
  const teamMember = cf.team_member || 'Catriona';
  const openingLine = cf.personalized_opening || '';
  const campaign = cf.campaign || 'QMSR';

  // Email templates by team member/campaign
  const templates = {
    'Catriona': {
      subject: 'QMSR is live: your QMS gaps just became compliance risks',
      signature: 'Catriona Boyd\nDirector, Quality Services\nAvania Clinical'
    },
    'Angela': {
      subject: 'QMSR is live—your first 90 days matter',
      signature: 'Angela Johnson\nGlobal MedTech Executive, Regulatory Affairs\nAvania Clinical'
    },
    'Sam': {
      subject: 'Your AI device needs a PCCP—here is why',
      signature: 'Sam Engelman\nDirector, Regulatory Affairs\nAvania Clinical'
    },
    'Jasmine': {
      subject: 'Strategic CRO partnership vs. transactional project work',
      signature: 'Jasmine Saba\nSVP, Strategic Relationships\nAvania Clinical'
    },
    'Jeannine': {
      subject: 'The medtech CRO built for companies like yours',
      signature: 'Jeannine Umpleby\nDirector, Business Development\nAvania Clinical'
    }
  };

  const template = templates[teamMember] || templates['Catriona'];

  // Build email body with personalized opening
  let body = '';

  if (teamMember === 'Catriona') {
    body = `${openingLine}\n\nSunday, February 2, FDA's Quality Management System Regulation officially replaced the Quality System Regulation. The companies that prepared have compliant systems today. The ones waiting are now facing urgent remediation with FDA inspections looming.\n\nWorth a 30-minute call this week to assess your current QMSR compliance status?\n\nBest regards,\n${template.signature}`;
  } else if (teamMember === 'Angela') {
    body = `${openingLine}\n\nThree days ago, FDA's Quality Management System Regulation officially replaced the Quality System Regulation. After 25 years navigating FDA regulatory transitions, I can tell you: the companies that get this right in the first 90 days avoid the scramble.\n\nWorth a 30-minute strategy call this week?\n\nBest regards,\n${template.signature}`;
  } else if (teamMember === 'Sam') {
    body = `${openingLine}\n\nIf your medical device uses machine learning, you have probably heard about PCCP. What you might not realize: PCCP is quickly becoming FDA's litmus test for whether you understand AI device regulation.\n\nWorth a 30-minute conversation to assess your PCCP readiness?\n\nBest regards,\n${template.signature}`;
  } else if (teamMember === 'Jasmine') {
    body = `${openingLine}\n\nMost medtech companies approach CRO relationships transactionally. Then they are surprised when the CRO delivers exactly what was asked for—but the broader business outcomes fall short.\n\nWorth a 30-minute conversation?\n\nBest regards,\n${template.signature}`;
  } else if (teamMember === 'Jeannine') {
    body = `${openingLine}\n\nQuick question: when you need regulatory strategy, clinical trial execution, and quality system support, are you working with three different vendors—or one integrated partner?\n\nAvania is the world's only medtech-exclusive CRO.\n\nWorth a brief conversation?\n\nBest regards,\n${template.signature}`;
  }

  // Use Avania workspace email - not individual team member emails
  return {
    json: {
      contactId: contact.id,
      email: contact.email,
      firstName: contact.firstName,
      teamMember: teamMember,
      emailSubject: template.subject,
      emailBody: body,
      fromEmail: 'team@avaniaclinical.com'  // Avania workspace email
    }
  };
});
